def main():
    en_path = "/sessions/modest-determined-dijkstra/mnt/Pulser.fit/website/assets/i18n/en.json"
    de_path = "/sessions/modest-determined-dijkstra/mnt/Pulser.fit/website/assets/i18n/de.json"

    with open(en_path, encoding="utf-8") as f:
        en = json.load(f)
    with open(de_path, encoding="utf-8") as f:
        de = json.load(f)

    new_translations = json.loads(TRANSLATIONS_JSON)

    result = {}
    already_translated = 0
    newly_translated = 0
    kept_as_is = 0

    for key, en_value in en.items():
        de_value = de.get(key)

        # If de has a genuine translation (different from en), keep it
        if de_value is not None and de_value != en_value:
            result[key] = de_value
            already_translated += 1
        # If we have a new translation, use it
        elif key in new_translations:
            result[key] = new_translations[key]
            newly_translated += 1
        else:
            # Keep as-is (numeric strings, brand names, symbols, etc.)
            result[key] = en_value
            kept_as_is += 1

    with open(de_path, "w", encoding="utf-8") as f:
        json.dump(result, f, ensure_ascii=False, indent=2)
        f.write("\n")

    print(f"Complete de.json written to {de_path}")
    print(f"  Already translated (kept):  {already_translated}")
    print(f"  Newly translated:           {newly_translated}")
    print(f"  Kept as-is (symbols/names): {kept_as_is}")
    print(f"  Total keys:                 {len(result)}")

    # Report any remaining untranslated keys
    remaining = {k: v for k, v in result.items() if v == en.get(k)}
    if remaining:
        print(f"\n  Untranslated keys ({len(remaining)} - kept as-is by design):")
        for k, v in list(remaining.items())[:20]:
            print(f"    {k}: {v[:60]}")


if __name__ == "__main__":
    main()
